import React, { useState, useEffect, useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Stars, PerspectiveCamera, Fog } from '@react-three/drei';
import * as THREE from 'three';

// --- Âú∞ÁêÉ„ÅÆ„Ç≥„É≥„Éù„Éº„Éç„É≥„Éà ---
const Earth = () => {
  const textureLoader = new THREE.TextureLoader();
  const colorMap = useMemo(() => textureLoader.load('https://raw.githubusercontent.com/mrdoob/three.js/master/examples/textures/planets/earth_atmos_2048.jpg'), []);
  const normalMap = useMemo(() => textureLoader.load('https://raw.githubusercontent.com/mrdoob/three.js/master/examples/textures/planets/earth_normal_2048.jpg'), []);
  const specularMap = useMemo(() => textureLoader.load('https://raw.githubusercontent.com/mrdoob/three.js/master/examples/textures/planets/earth_specular_2048.jpg'), []);

  return (
    <mesh rotation={[0, Math.PI / 2, 0]}>
      <sphereGeometry args={[2, 64, 64]} />
      <meshPhongMaterial
        map={colorMap}
        normalMap={normalMap}
        specularMap={specularMap}
        shininess={5}
      />
    </mesh>
  );
};

// --- „É°„Ç§„É≥„Ç¢„Éó„É™ ---
function App() {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatTime = (date) => {
    return date.toLocaleTimeString('en-GB', { hour12: false });
  };

  const formatDate = (date) => {
    const options = { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' };
    return date.toLocaleDateString('ja-JP', options);
  };

  return (
    <div style={{ width: '100vw', height: '100vh', background: '#000', overflow: 'hidden' }}>
      {/* UIË¶ÅÁ¥Ý */}
      <div style={styles.container}>
        <div style={styles.title}>ÊÉÖÂÝ±</div>
        <div style={styles.time}>{formatTime(time)}</div>
        <div style={styles.date}>{formatDate(time)}</div>
      </div>

      <Canvas shadows>
        <PerspectiveCamera makeDefault position={[0, 0, 6]} />
        <Fog attach="fog" args={['#000', 5, 15]} />
        <ambientLight intensity={0.2} />
        <pointLight position={[10, 10, 10]} intensity={1.5} castShadow />
        <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

        <Earth />

        <OrbitControls 
          enablePan={false} 
          enableZoom={true} 
          autoRotate={true} 
          autoRotateSpeed={0.5} 
        />
      </Canvas>
    </div>
  );
}

// --- „Éá„Ç∂„Ç§„É≥Ë®≠ÂÆöÔºà„Åì„Åì„ÇíË™øÊï¥„Åó„Åæ„Åó„ÅüÔºâ ---
const styles = {
  container: {
    position: 'absolute',
    top: '50px',
    left: '50px',
    color: 'white',
    zIndex: 10,
    pointerEvents: 'none',
    fontFamily: '-apple-system, BlinkMacSystemFont, "Helvetica Neue", "Segoe UI", Hiragino Kaku Gothic ProN, sans-serif',
  },
  title: {
    fontSize: '11px',
    fontWeight: '200',        // Ê•µÁ¥∞
    letterSpacing: '0.4em',   // Â≠óÈñì„ÇíÂ∫É„ÇÅ„Å´
    marginBottom: '2px',
    color: 'rgba(255, 255, 255, 0.4)', // „Åã„Å™„ÇäËñÑ„Åè
    textTransform: 'uppercase',
  },
  time: {
    fontSize: '64px',         // Â§ß„Åç„Åè
    fontWeight: '400',        // Ê®ôÊ∫ñ
    lineHeight: '1.1',
    fontFamily: '"SF Mono", "Roboto Mono", Menlo, monospace',
    fontVariantNumeric: 'tabular-nums',
    textShadow: '0 0 20px rgba(0,0,0,0.5)',
  },
  date: {
    fontSize: '12px',
    fontWeight: '300',
    marginTop: '4px',
    color: 'rgba(255, 255, 255, 0.7)',
    letterSpacing: '0.05em',
  }
};

export default App;
